### 任务 3: 添加 WebSocket 性能测试 ⚡ **P1 - 重要**

**问题描述**: 缺少 WebSocket 实时通信性能测试

**解决方案**:

**文件**: `tests/performance/websocket-perf.test.ts`

```typescript
import { describe, it, expect, beforeAll, afterAll } from '@jest/globals'
import { WebSocketServer } from 'ws'
import { DashboardWebSocket } from '../src/dashboard/server/services/websocket.service'

describe('WebSocket Performance Tests', () => {
  let wss: WebSocketServer
  let port: number

  beforeAll(async () => {
    // 启动测试 WebSocket 服务器
    wss = new WebSocketServer({ port: 0 })
    port = (wss.address() as any).port
  })

  afterAll(() => {
    wss.close()
  })

  it('handles 100 concurrent connections', async () => {
    const connections: DashboardWebSocket[] = []
    const connectPromises: Promise<void>[] = []

    // 创建 100 个并发连接
    for (let i = 0; i < 100; i++) {
      const ws = new DashboardWebSocket()
      connections.push(ws)
      connectPromises.push(
        new Promise((resolve) => {
          ws.connect(`ws://localhost:${port}`)
          ws.on('open', () => resolve())
        })
      )
    }

    const startTime = Date.now()
    await Promise.all(connectPromises)
    const duration = Date.now() - startTime

    expect(duration).toBeLessThan(5000) // 5秒内完成
    expect(connections).toHaveLength(100)

    // 清理
    connections.forEach(ws => ws.disconnect())
  })

  it('broadcasts to 100 clients in < 100ms', async () => {
    const clients: DashboardWebSocket[] = []
    const received: number[] = []

    // 创建 100 个客户端
    for (let i = 0; i < 100; i++) {
      const ws = new DashboardWebSocket()
      ws.connect(`ws://localhost:${port}`)
      ws.on('test-event', (data) => {
        received.push(Date.now())
      })
      clients.push(ws)
    }

    // 等待所有连接建立
    await new Promise(resolve => setTimeout(resolve, 500))

    // 广播消息
    const startTime = Date.now()
    wss.clients.forEach(client => {
      if (client.readyState === 1) {
        client.send(JSON.stringify({ event: 'test-event', data: {} }))
      }
    })

    // 等待所有消息到达
    await new Promise(resolve => setTimeout(resolve, 200))
    const endTime = Date.now()

    expect(received).toHaveLength(100)
    expect(endTime - startTime).toBeLessThan(100)

    // 清理
    clients.forEach(ws => ws.disconnect())
  })

  it('handles 1000 messages per second', async () => {
    const ws = new DashboardWebSocket()
    let receivedCount = 0

    ws.connect(`ws://localhost:${port}`)
    ws.on('test-event', () => {
      receivedCount++
    })

    await new Promise(resolve => setTimeout(resolve, 500))

    // 发送 1000 条消息
    const startTime = Date.now()
    for (let i = 0; i < 1000; i++) {
      wss.clients.forEach(client => {
        if (client.readyState === 1) {
          client.send(JSON.stringify({ event: 'test-event', data: { index: i } }))
        }
      })
    }

    // 等待接收完成
    await new Promise(resolve => setTimeout(resolve, 2000))
    const duration = (Date.now() - startTime) / 1000

    expect(receivedCount).toBeGreaterThanOrEqual(1000)
    expect(duration).toBeLessThan(2) // 2秒内完成

    ws.disconnect()
  })
})
```

**预期成果**:
- ✅ WebSocket 并发连接测试通过
- ✅ 广播延迟 < 100ms
- ✅ 消息吞吐量 > 1000 msg/s

**时间**: 1 天

