import { describe, it, expect, beforeAll, afterAll } from '@jest/globals'
import { FastifyInstance } from 'fastify'
import { WebSocket } from 'ws'
import { buildServer } from '../../src/dashboard/server'
import { AutoIterationEngine } from '../../src/auto-iteration'

describe('Dashboard Integration Tests', () => {
  let app: FastifyInstance
  let wsClient: WebSocket
  let port: number

  beforeAll(async () => {
    app = await buildServer()
    await app.listen({ port: 0 })
    port = (app.server.address() as any).port
  })

  afterAll(async () => {
    wsClient?.close()
    await app.close()
  })

  it('connects to WebSocket and receives updates', async () => {
    return new Promise((resolve, reject) => {
      wsClient = new WebSocket(`ws://localhost:${port}/api/ws`)

      wsClient.on('open', () => {
        console.log('WebSocket connected')
      })

      wsClient.on('message', (data) => {
        const message = JSON.parse(data.toString())
        expect(message).toHaveProperty('event')
        expect(message).toHaveProperty('data')
        resolve(true)
      })

      wsClient.on('error', reject)

      // 超时保护
      setTimeout(() => reject(new Error('Timeout')), 5000)
    })
  })

  it('integrates with AutoIterationEngine', async () => {
    const engine = new AutoIterationEngine({
      projectPath: process.cwd(),
      intervalMs: 60000,
      maxIterations: 1,
      autoCommit: false,
      autoPush: false,
      permissionMode: 'bypassPermissions',
    })

    // 监听 WebSocket 事件
    const events: any[] = []
    wsClient.on('message', (data) => {
      events.push(JSON.parse(data.toString()))
    })

    // 启动引擎
    await engine.start()

    // 等待事件
    await new Promise(resolve => setTimeout(resolve, 2000))

    // 验证接收到事件
    expect(events.length).toBeGreaterThan(0)
    expect(events.some(e => e.event === 'iteration.status_changed')).toBe(true)
  })
})
```

**预期成果**:
- ✅ Dashboard 与 AutoIterationEngine 集成测试通过
- ✅ WebSocket 事件流验证
- ✅ 端到端流程测试覆盖

